WITH nearest AS (SELECT p.nom, p.source, (SELECT v.id FROM ways_vertices_pgr v ORDER BY v.geom <-> p.geom LIMIT 1) AS vid FROM mission_pois p WHERE p.role = 'attaque'), pairs AS (SELECT a.nom AS from_name, a.source AS from_src, b.nom AS to_name, b.source AS to_src, a.vid AS from_vid, b.vid AS to_vid FROM nearest a, nearest b WHERE a.vid <> b.vid AND a.source < b.source LIMIT 5), routes AS (SELECT p.from_name, p.to_name, (SELECT sum(cost) FROM pgr_dijkstra('SELECT id, source, target, cost, reverse_cost FROM ways WHERE cost IS NOT NULL', p.from_vid, p.to_vid, directed := false) WHERE edge != -1) AS dist_m FROM pairs p) SELECT * FROM routes WHERE dist_m IS NOT NULL ORDER BY dist_m LIMIT 5;
